// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

contract MultiSigWallet {
    error NotOwner();
    error AlreadyExecuted();
    error AlreadyApproved();
    error InsufficientBalance();

    event Proposed(uint256 proposalId, address to, uint256 amount);
    event Approved(uint256 proposalId, address approver);
    event Executed(uint256 proposalId);

    struct Proposal {
        address to;
        uint256 amount;
        uint8 approvalCount;
        bool executed;
        mapping(address => bool) approved;
    }

    address[3] public owners;
    mapping(address => bool) public isOwner;
    Proposal[] public proposalsStorage;

    constructor(address[3] memory _owners) payable {
        for (uint i = 0; i < 3; i++) {
            owners[i] = _owners[i];
            isOwner[_owners[i]] = true;
        }
    }

    receive() external payable {}

    function propose(address to, uint256 amount) external returns (uint256) {
        if (!isOwner[msg.sender]) revert NotOwner();
        uint256 id = proposalsStorage.length;
        [[SLOT alloc_proposal]]
        p.to = to;
        p.amount = amount;
        p.approvalCount = 1;
        [[SLOT approve_set]]
        emit Proposed(id, to, amount);
        return id;
    }

    function approve(uint256 proposalId) external {
        if (!isOwner[msg.sender]) revert NotOwner();
        Proposal storage p = proposalsStorage[proposalId];
        if (p.executed) revert AlreadyExecuted();
        if (p.approved[msg.sender]) revert AlreadyApproved();
        p.approved[msg.sender] = true;
        p.approvalCount++;
        emit Approved(proposalId, msg.sender);
        if ([[SLOT quorum_check]]) {
            if (address(this).balance < p.amount) revert InsufficientBalance();
            p.executed = true;
            [[SLOT send_funds]]
            emit Executed(proposalId);
        }
    }

    function proposals(uint256 id) external view returns (address to, uint256 amount, uint8 approvalCount, bool executed) {
        Proposal storage p = proposalsStorage[id];
        return (p.to, p.amount, p.approvalCount, p.executed);
    }
}
